body.script:
document.addEventListener("DOMContentLoaded", function () {
    const placeholder = document.querySelector('.placeholder');
    const footer      = document.querySelector('footer');
    window.addEventListener('resize', onResize);
    updateHolderHeight(); checkFooterHeight();
    function onResize() { updateHolderHeight(); checkFooterHeight(); }
    function updateHolderHeight() { placeholder.style.height = footer.offsetHeight + 'px'; }
    function checkFooterHeight() {
        if (footer.offsetHeight > window.innerHeight) {
            window.addEventListener('scroll', onScroll);
            footer.style.bottom = 'unset'; footer.style.top = '0px';
        } else {
            window.removeEventListener('scroll', onScroll);
            footer.style.top = 'unset'; footer.style.bottom = '0px';
        }
    }
    let placeholderTop, ticking;
    function onScroll() { placeholderTop = Math.round(placeholder.getBoundingClientRect().top); requestTick(); }
    function requestTick() { if (!ticking) requestAnimationFrame(updateBasedOnScroll); ticking = true; }
    function updateBasedOnScroll() { ticking = false; if (placeholderTop <= 0) footer.style.top = placeholderTop + 'px'; }
});
